import React, { useMemo, useState } from 'react';
import './Dashboard.css';

const historyData = [
  {
    id: 1,
    title: '야근 후 감정 정리 대화',
    preview: '괜찮은 척하고 있었는데 사실 많이 지쳤다는 이야기를 나눴어요.',
    mood: '피로 · 답답함',
    character: '하루',
    duration: '18분',
    date: '2026.03.31',
    important: true,
  },
  {
    id: 2,
    title: '취업 불안에 대한 대화',
    preview: '비교로 인한 불안과 자신감 저하에 대해 루미와 이야기했어요.',
    mood: '불안 · 자기비교',
    character: '루미',
    duration: '24분',
    date: '2026.03.30',
    important: true,
  },
  {
    id: 3,
    title: '저녁 외로움 패턴 체크',
    preview: '혼자 있는 시간에 감정이 커지는 흐름을 메이티가 먼저 짚어줬어요.',
    mood: '외로움 · 공허함',
    character: '하루',
    duration: '11분',
    date: '2026.03.29',
    important: false,
  },
  {
    id: 4,
    title: '조금 가벼웠던 하루 회고',
    preview: '기분이 비교적 편안했던 하루를 돌아보며 긍정 감정을 기록했어요.',
    mood: '안정 · 편안함',
    character: '루미',
    duration: '9분',
    date: '2026.03.28',
    important: false,
  },
];

function ChatHistory() {
  const [query, setQuery] = useState('');
  const [filter, setFilter] = useState('all');

  const filteredItems = useMemo(() => {
    return historyData.filter((item) => {
      const matchQuery =
        item.title.toLowerCase().includes(query.toLowerCase()) ||
        item.preview.toLowerCase().includes(query.toLowerCase()) ||
        item.mood.toLowerCase().includes(query.toLowerCase());

      if (!matchQuery) return false;

      if (filter === 'important') return item.important;
      if (filter === 'recent') return item.date >= '2026.03.30';
      return true;
    });
  }, [query, filter]);

  return (
    <section className="dashboard-page">
      <div className="dashboard-shell">
        <div className="dashboard-page-head">
          <div>
            <span className="panel-eyebrow">Conversation Archive</span>
            <h1>대화 기록</h1>
            <p>메이티와 나눈 감정 대화를 다시 살펴보고, 패턴을 더 깊게 이해해보세요.</p>
          </div>
        </div>

        <div className="history-toolbar">
          <div className="history-search">
            <input
              type="text"
              placeholder="제목, 감정 키워드, 대화 내용 검색"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
          </div>

          <div className="history-filter-group">
            <button
              className={filter === 'all' ? 'active' : ''}
              onClick={() => setFilter('all')}
            >
              전체
            </button>
            <button
              className={filter === 'important' ? 'active' : ''}
              onClick={() => setFilter('important')}
            >
              중요
            </button>
            <button
              className={filter === 'recent' ? 'active' : ''}
              onClick={() => setFilter('recent')}
            >
              최근
            </button>
          </div>
        </div>

        <div className="history-grid">
          {filteredItems.map((item) => (
            <article key={item.id} className="history-card">
              <div className="history-card-top">
                <div className="history-card-tags">
                  <span>{item.character}</span>
                  <span>{item.duration}</span>
                </div>
                {item.important && <div className="history-important">중요</div>}
              </div>

              <h3>{item.title}</h3>
              <p>{item.preview}</p>

              <div className="history-mood-row">
                <span className="history-mood-label">감정 라벨</span>
                <strong>{item.mood}</strong>
              </div>

              <div className="history-card-bottom">
                <span>{item.date}</span>
                <button>대화 다시 보기</button>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

export default ChatHistory;
